type MaskToken =
    | { t: "digit" }
    | { t: "alpha" }
    | { t: "alphanum" }
    | { t: "lit"; v: string };

function isDigit(c: string) { return /^[0-9]$/.test(c); }
function isAlpha(c: string) { return /^[A-Za-z]$/.test(c); }
function isAlphaNum(c: string) { return /^[A-Za-z0-9]$/.test(c); }

export function tokenizeMask(mask: string): { tokens: MaskToken[]; optionalFrom: number } {
    const q = mask.indexOf("?");
    const main = q >= 0 ? mask.slice(0, q) : mask;

    const tokens: MaskToken[] = [];
    for (const ch of main) {
        if (ch === "9") tokens.push({ t: "digit" });
        else if (ch === "a") tokens.push({ t: "alpha" });
        else if (ch === "*") tokens.push({ t: "alphanum" });
        else tokens.push({ t: "lit", v: ch });
    }

    return { tokens, optionalFrom: q >= 0 ? tokens.length : Number.POSITIVE_INFINITY };
}

/**
 * Formats raw input into masked output; returns both masked and unmasked.
 * - slotChar is only used for display if you want “_”; here we keep it minimal.
 */
export function formatWithMask(raw: string, mask: string): { masked: string; unmasked: string } {
    const { tokens } = tokenizeMask(mask);
    const src = raw.split("");
    let si = 0;

    let masked = "";
    let unmasked = "";

    for (const token of tokens) {
        if (token.t === "lit") {
            masked += token.v;
            continue;
        }

        // advance source until it matches token
        while (si < src.length) {
            const c = src[si++] ?? '';
            const ok =
                token.t === "digit" ? isDigit(c)
                    : token.t === "alpha" ? isAlpha(c)
                        : isAlphaNum(c);

            if (ok) {
                masked += c;
                unmasked += c;
                break;
            }
        }

        // if no source left, stop (don’t pad)
        if (si >= src.length && masked.length === 0) break;
    }

    return { masked, unmasked };
}
